INSERT INTO contract_templates (contract_type, jurisdiction, version, title, preamble, recitals, clauses, signature_block, placeholders, is_active, metadata) VALUES (
  'freelance_service',
  'us_new_york',
  1,
  'Freelance Services Agreement (New York)',
  'This Freelance Services Agreement (the "Agreement") is entered into as of {{effective_date}} (the "Effective Date"), by and between {{party_a_company}} ("Hiring Party"), with address at {{party_a_address}}, and {{party_b_name}} doing business as {{party_b_company}} ("Freelance Worker"), with address at {{party_b_address}}.',
  'WHEREAS, Hiring Party wishes to engage Freelance Worker to provide certain freelance services;
WHEREAS, Freelance Worker wishes to provide such services on the terms set out in this Agreement;
WHEREAS, the parties intend this Agreement to comply with applicable New York law, including the New York Freelance Isn''t Free Act (New York City Administrative Code § 20-927 et seq. and/or New York Labor Law Article 44, as applicable);
NOW, THEREFORE, in consideration of the mutual covenants herein, the parties agree as follows:',
  '[{"id":"services","title":"1. SERVICES","content":"1.1 Services. Freelance Worker shall provide the services described in {{services_description}} (the \"Services\").\n\n1.2 Standard. Freelance Worker shall perform the Services professionally, meeting applicable industry standards.\n\n1.3 Deliverables. Freelance Worker shall deliver any work products as specified in {{services_description}}.\n\n1.4 Timeline. Freelance Worker shall complete the Services within the timeframe set out in {{services_description}}.\n\n1.5 Changes. Changes to the Services must be agreed in writing.","type":"standard","order":1},{"id":"payment","title":"2. PAYMENT (FREELANCE ISN''T FREE ACT COMPLIANCE)","content":"2.1 Compensation. Hiring Party shall pay Freelance Worker: (a) a project fee of {{payment_amount}}; and/or (b) {{hourly_rate}} per hour, as specified in {{services_description}}.\n\n2.2 Payment Date. Except as otherwise agreed in writing, Hiring Party shall pay Freelance Worker: (a) for contracts where the value is $800 or more and completed in 120 days or less, within 30 days of completion of the Services (or if the contract provides for payment upon occurrence of a milestone, within 30 days after such milestone occurs); or (b) for ongoing contracts, in accordance with the payment schedule specified in {{services_description}}.\n\n2.3 Invoicing. Freelance Worker shall invoice Hiring Party as set out in {{services_description}}, or upon completion if not specified.\n\n2.4 Late Payment. In the event of late payment where the total compensation is $800 or more, Freelance Worker may be entitled to double damages, injunctive relief, and attorneys'' fees as provided under applicable law.\n\n2.5 Expenses. Freelance Worker is responsible for all expenses unless pre-approved in writing.\n\n2.6 Taxes. Freelance Worker is responsible for all taxes on fees received, including New York State and City income taxes. Hiring Party will not withhold payroll taxes.","type":"standard","order":2},{"id":"freelancer_status","title":"3. FREELANCE WORKER STATUS","content":"3.1 Independent Contractor. Freelance Worker is an independent contractor, not an employee or agent of Hiring Party.\n\n3.2 Control. Freelance Worker determines how, when, and where to perform the Services, subject to meeting agreed deliverables and deadlines.\n\n3.3 Equipment. Freelance Worker shall provide their own equipment, tools, and materials.\n\n3.4 No Exclusivity. Freelance Worker may work for other clients, provided this does not conflict with obligations under this Agreement.\n\n3.5 No Benefits. Freelance Worker is not entitled to employee benefits.\n\n3.6 New York Classification. The Parties intend that Freelance Worker be properly classified as an independent contractor under applicable New York law.","type":"standard","order":3},{"id":"term","title":"4. TERM AND TERMINATION","content":"4.1 Term. This Agreement runs from the Effective Date until {{expiration_date}}, or until the Services are completed, unless terminated earlier.\n\n4.2 Termination for Convenience. Either party may terminate by giving {{notice_period}} days'' written notice.\n\n4.3 Termination for Cause. Either party may terminate immediately if the other: (a) materially breaches and fails to cure within 7 days of notice; (b) becomes insolvent; or (c) commits fraud.\n\n4.4 Effect. Upon termination: (a) Freelance Worker stops work and delivers completed work; (b) Hiring Party pays for work completed through termination date, in accordance with applicable payment deadlines.","type":"standard","order":4},{"id":"intellectual_property","title":"5. INTELLECTUAL PROPERTY","content":"5.1 Work Product. \"Work Product\" means all materials created by Freelance Worker in performing the Services.\n\n5.2 Assignment. Upon full payment, Freelance Worker assigns all intellectual property rights in the Work Product to Hiring Party.\n\n5.3 Background IP. Freelance Worker retains pre-existing IP (\"Background IP\"). If Background IP is included in Work Product, Freelance Worker grants Hiring Party a perpetual, royalty-free license to use it.\n\n5.4 Moral Rights. Freelance Worker waives moral rights in the Work Product to the extent permitted by law.\n\n5.5 Portfolio. Unless otherwise agreed, Freelance Worker may display completed Work Product in their portfolio for self-promotion.","type":"negotiable","order":5},{"id":"confidentiality","title":"6. CONFIDENTIALITY","content":"6.1 Confidential Information. Each party shall keep confidential any non-public information received from the other that is designated confidential or should reasonably be understood as confidential.\n\n6.2 Obligations. Confidential Information shall be: (a) used only for this Agreement; (b) protected with reasonable care; (c) not disclosed except to those who need to know.\n\n6.3 Exclusions. Excludes information that is: public, already known, received from third parties, or independently developed.\n\n6.4 Defend Trade Secrets Act Notice. Pursuant to 18 U.S.C. § 1833(b), an individual shall not be held liable for disclosure of a trade secret made in confidence for reporting suspected violations of law.\n\n6.5 Duration. Confidentiality obligations survive termination for {{confidentiality_period}} years.","type":"standard","order":6},{"id":"warranties","title":"7. WARRANTIES","content":"7.1 Freelance Worker Warranties. Freelance Worker warrants that: (a) they have authority to enter this Agreement; (b) Services will be performed professionally; (c) Work Product will be original and not infringe third-party rights; (d) they have the right to assign IP in Work Product.\n\n7.2 Hiring Party Warranties. Hiring Party warrants that: (a) they have authority to enter this Agreement; (b) materials provided to Freelance Worker do not infringe third-party rights.\n\n7.3 Disclaimer. Except as stated, neither party makes additional warranties.","type":"standard","order":7},{"id":"liability","title":"8. LIABILITY","content":"8.1 Limitation. Neither party is liable for indirect or consequential damages. Total liability is limited to the fees paid or payable under this Agreement.\n\n8.2 Exceptions. Nothing limits liability for fraud, willful misconduct, or matters that cannot be limited by law.\n\n8.3 Insurance. Freelance Worker is advised to maintain appropriate professional liability insurance.\n\n8.4 Freelance Isn''t Free Act. Notwithstanding the foregoing, nothing in this Section limits Freelance Worker''s rights or Hiring Party''s obligations under applicable freelance worker protection laws, including the right to recover double damages, attorneys'' fees, and other relief as provided by law.","type":"negotiable","order":8},{"id":"dispute_resolution","title":"9. DISPUTE RESOLUTION; RETALIATION PROHIBITED","content":"9.1 Good Faith Resolution. The parties shall attempt to resolve any dispute arising out of this Agreement in good faith through informal negotiation.\n\n9.2 No Retaliation. Hiring Party shall not take any adverse action against Freelance Worker, including threatening, intimidating, disciplining, harassing, blacklisting, or denying future work, for exercising any right under this Agreement or applicable law, including the Freelance Isn''t Free Act.\n\n9.3 Complaint Rights. Freelance Worker has the right to file a complaint with the applicable New York agency (such as the NYC Department of Consumer and Worker Protection or New York State Department of Labor) regarding any violations of applicable freelance worker protection laws.","type":"standard","order":9},{"id":"general","title":"10. GENERAL PROVISIONS","content":"10.1 Governing Law. This Agreement is governed by the laws of the State of New York, without regard to conflict of laws principles.\n\n10.2 Venue. The parties consent to exclusive jurisdiction of the state and federal courts in {{venue_county}} County, New York.\n\n10.3 Notices. Notices shall be in writing, delivered by hand, mail, or email.\n\n10.4 Assignment. Neither party may assign without consent, except to a successor entity.\n\n10.5 Entire Agreement. This Agreement is the entire agreement. Amendments must be in writing.\n\n10.6 Severability. Invalid provisions are enforced to the maximum extent permitted.\n\n10.7 Waiver. Waivers must be in writing.\n\n10.8 Force Majeure. Neither party is liable for delays beyond reasonable control.\n\n10.9 Counterparts. May be signed in counterparts, including electronically under New York ESRA and the federal ESIGN Act.\n\n10.10 Record Retention. Hiring Party shall retain a copy of this Agreement for at least six (6) years after termination, as required by applicable law.","type":"standard","order":10}]'::jsonb,
  'IN WITNESS WHEREOF, the parties have executed this Agreement as of {{signature_date}}.

HIRING PARTY:
{{party_a_company}}

By: ______________________________
Printed Name: {{party_a_name}}
