Email: {{party_a_email}}
Date: {{signature_date}}

FREELANCE WORKER:
{{party_b_company}}

By: ______________________________
Printed Name: {{party_b_name}}
Email: {{party_b_email}}
Date: {{signature_date}}',
  '[{"id":"party_a_email","token":"{{party_a_email}}","label":"Your Email","description":"Hiring party email","category":"party_a","type":"email","required":true,"autofillKey":"email"},{"id":"party_a_name","token":"{{party_a_name}}","label":"Your Name","description":"Hiring party name","category":"party_a","type":"text","required":true,"autofillKey":"name"},{"id":"party_a_address","token":"{{party_a_address}}","label":"Your Address","description":"Hiring party address","category":"party_a","type":"textarea","required":false,"autofillKey":"address"},{"id":"party_a_company","token":"{{party_a_company}}","label":"Your Company","description":"Hiring party company","category":"party_a","type":"text","required":false,"autofillKey":"company_name"},{"id":"party_a_title","token":"{{party_a_title}}","label":"Your Title","description":"Job title","category":"party_a","type":"text","required":false,"autofillKey":"job_title"},{"id":"party_b_email","token":"{{party_b_email}}","label":"Freelancer Email","description":"Freelance worker email","category":"party_b","type":"email","required":true},{"id":"party_b_name","token":"{{party_b_name}}","label":"Freelancer Name","description":"Freelance worker name","category":"party_b","type":"text","required":true},{"id":"party_b_address","token":"{{party_b_address}}","label":"Freelancer Address","description":"Freelance worker address","category":"party_b","type":"textarea","required":false},{"id":"party_b_company","token":"{{party_b_company}}","label":"Business Name","description":"Freelance worker business name","category":"party_b","type":"text","required":false},{"id":"effective_date","token":"{{effective_date}}","label":"Start Date","description":"Agreement start date","category":"dates","type":"date","required":true},{"id":"expiration_date","token":"{{expiration_date}}","label":"End Date","description":"Agreement end date","category":"dates","type":"date","required":false},{"id":"signature_date","token":"{{signature_date}}","label":"Signature Date","description":"Date of signing","category":"dates","type":"date","required":false},{"id":"venue_county","token":"{{venue_county}}","label":"Venue County","description":"New York county for legal venue","category":"terms","type":"text","required":true},{"id":"notice_period","token":"{{notice_period}}","label":"Notice Period","description":"Days notice for termination","category":"terms","type":"number","required":false},{"id":"confidentiality_period","token":"{{confidentiality_period}}","label":"Confidentiality Period","description":"Years of confidentiality obligation","category":"terms","type":"number","required":false},{"id":"hourly_rate","token":"{{hourly_rate}}","label":"Hourly Rate","description":"Rate per hour","category":"financial","type":"currency","required":false},{"id":"payment_amount","token":"{{payment_amount}}","label":"Project Fee","description":"Total project fee","category":"financial","type":"currency","required":false},{"id":"services_description","token":"{{services_description}}","label":"Services","description":"Description of services","category":"project","type":"textarea","required":false}]'::jsonb,
  true,
  '{"generator_version":"2.0-jurisdiction-expansion","jurisdiction":"us_new_york","generated_at":"2025-12-28T18:00:00.000Z","word_count":2000,"clause_count":10,"placeholder_count":18,"note":"Includes NYC/NY Freelance Isnt Free Act compliance provisions"}'::jsonb
